final:
module UpDownCounter_3bit(
   input                clk ,
   input                rst_n,
   input                up_down,

   output reg [2:0]     obf_Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) obf_Q <= 3'b0;
        else if(up_down) obf_Q <= obf_Q + 1;
        else obf_Q <= obf_Q - 1;
    end
endmodule
